func searchKindClass(kind string) string {
	switch kind {
	case "project":
		return "bg-indigo-500/15 text-indigo-400"
	case "community":
		return "bg-emerald-500/15 text-emerald-400"
	case "team":
		return "bg-amber-500/15 text-amber-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func searchNodeKindClass(kind string) string {
	switch kind {
	case "task":
		return "bg-indigo-500/15 text-indigo-400"
	case "post":
		return "bg-emerald-500/15 text-emerald-400"
	case "thread":
		return "bg-amber-500/15 text-amber-400"
	case "conversation":
		return "bg-sky-500/15 text-sky-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func searchStateClass(state string) string {
	switch state {
	case "open":
		return "bg-warm-faint/20 text-warm-muted"
	case "active":
		return "bg-indigo-500/15 text-indigo-400"
	case "done":
		return "bg-emerald-500/15 text-emerald-400"
	default:
		return ""
	}
}

func truncateSearch(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n] + "..."
}

